    --primary: 220 90% 56%;
    --primary-foreground: 0 0% 100%;
  }
}
```

### Component Props

Most components accept standard styling props:

```tsx
<PricingTableOne 
  plans={plans}
  onSelectPlan={handleSelect}
  className="max-w-4xl mx-auto"
  containerClassName="gap-8"
